    40→	renderSearchPageHtml({ result }: { result: NeuralSearchResponseDto | null }): string {
    41→		const queryValue = result?.query ?? '';
    42→
    43→		const productCards = result
    44→			? result.products
    45→					.map(
    46→						(p) => `
    47→			<div style="border:1px solid #ddd;border-radius:8px;padding:12px;width:220px;text-align:center;background:#fff;display:flex;flex-direction:column;align-items:center;">
    48→				<img src="${p.style_card_image_url ?? ''}" alt="${p.name}" style="width:200px;height:200px;object-fit:contain;border-radius:4px;" onerror="this.src='data:image/svg+xml,<svg xmlns=%22http://www.w3.org/2000/svg%22 width=%22200%22 height=%22200%22><rect fill=%22%23eee%22 width=%22200%22 height=%22200%22/><text x=%2250%%22 y=%2250%%22 dominant-baseline=%22middle%22 text-anchor=%22middle%22 fill=%22%23999%22 font-size=%2214%22>No Image</text></svg>'"/>
    49→				<div style="margin-top:8px;font-weight:600;font-size:14px;min-height:40px;">${p.name}</div>
    50→				<div style="color:#555;font-size:12px;margin-top:4px;">${p.primary_category_name ?? ''}</div>
    51→				<div style="color:#666;font-size:11px;margin-top:2px;">${p.product_type ?? ''}</div>
    52→				<div style="color:#777;font-size:11px;margin-top:2px;">${p.manufacturer ?? ''}</div>
    53→				<div style="color:#888;font-size:11px;margin-top:2px;">${p.brand?.join(', ') ?? ''}</div>
    54→			</div>`,
    55→					)
    56→					.join('')
    57→			: '';
    58→
    59→		const resultsSection = result
    60→			? `<p style="margin:16px 0 8px;">Query: <strong>${result.query}</strong> | Results: ${result.total}</p>
    61→			<div style="display:flex;flex-wrap:wrap;gap:16px;">${productCards}</div>`
    62→			: '';
    63→
    64→		return `<!DOCTYPE html>
    65→<html><head><meta charset="utf-8"><title>Neural Search</title></head>
    66→<body style="font-family:system-ui,sans-serif;margin:20px;background:#f5f5f5;">
    67→	<h2>Neural Search</h2>
    68→	<form id="searchForm" style="display:flex;gap:8px;margin-bottom:16px;">
    69→		<input id="searchInput" name="q" type="text" value="${queryValue}" placeholder="Describe what you're looking for..."
    70→			style="flex:1;max-width:500px;padding:10px 14px;font-size:15px;border:1px solid #ccc;border-radius:6px;outline:none;" />
    71→		<button type="submit"
    72→			style="padding:10px 20px;font-size:15px;background:#2563eb;color:#fff;border:none;border-radius:6px;cursor:pointer;">
    73→			Ask AI
    74→		</button>
    75→	</form>
    76→	<div id="results">${resultsSection}</div>
    77→	<script>
    78→		document.getElementById('searchForm').addEventListener('submit', function(e) {
    79→			e.preventDefault();
    80→			var q = document.getElementById('searchInput').value.trim();
    81→			if (q) window.location.href = '/api/v1/neural-search/view?q=' + encodeURIComponent(q);
    82→		});
    83→	</script>
    84→</body></html>`;
    85→	}
    86→}
