     6→import { OpensearchService } from '@modules/opensearch/opensearch.service';
     7→
     8→import { NEURAL_SEARCH_MAX_QUERY_LENGTH } from '@constants/common.constant';
     9→import { OPENSEARCH_INDEX_NAME } from '@constants/env-variables.constant';
    10→import { NEURAL_SEARCH_KNOWN_BRANDS } from '@constants/neural-search-brands.constant';
    11→
    12→import { IOpensearchProduct } from '@interfaces/opensearch-product.interface';
    13→
    14→import { LogExecution } from '@decorators/log-execution.decorator';
    15→
    16→const MODEL_REFRESH_INTERVAL_MS = 5 * 60 * 1000;
    17→
    18→const MODEL_GROUP_NAME = 'neural-search-model-group';
    19→
    20→@Injectable()
    21→export class OpensearchNeuralService implements OnModuleInit {
    22→	private readonly logger = new Logger(OpensearchNeuralService.name);
    23→	private indexName: string;
    24→	private modelId: string | null = null;
    25→
    26→	constructor(
    27→		private readonly opensearchService: OpensearchService,
    28→		private readonly configService: EnvConfigService,
    29→	) {}
    30→
    31→	async onModuleInit(): Promise<void> {
    32→		this.indexName = this.configService.get<string>({ key: OPENSEARCH_INDEX_NAME });
    33→		await this.resolveModelId();
    34→	}
    35→
    36→	@Interval(MODEL_REFRESH_INTERVAL_MS)
    37→	async refreshModelId(): Promise<void> {
    38→		await this.resolveModelId();
    39→	}
    40→
    41→	private async resolveModelId(): Promise<void> {
    42→		try {
    43→			const modelId = await this.opensearchService.findDeployedModelId({
    44→				modelGroupName: MODEL_GROUP_NAME,
    45→			});
    46→
    47→			if (modelId && modelId !== this.modelId) {
    48→				const previousModelId = this.modelId;
    49→				this.modelId = modelId;
    50→				this.logger.log(`Model ID updated: ${previousModelId ?? 'none'} -> ${modelId}`);
    51→			} else if (!modelId) {
    52→				this.logger.warn(
    53→					'No deployed model found. Neural search will not work until bootstrap is run.',
    54→				);
    55→			}
    56→		} catch {
    57→			this.logger.warn('Failed to resolve model ID. OpenSearch may not be available.');
    58→		}
    59→	}
    60→
    61→	private getModelId(): string {
    62→		if (!this.modelId) {
    63→			throw new Error(
    64→				'Neural search model not available. Run: npm run cli:dev -- bootstrap-neural-search',
    65→			);
    66→		}
    67→		return this.modelId;
    68→	}
