    70→	private detectBrand({ text }: { text: string }): string | null {
    71→		const sorted = [...NEURAL_SEARCH_KNOWN_BRANDS].sort((a, b) => b.length - a.length);
    72→		for (const brand of sorted) {
    73→			const escaped = brand.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    74→			if (new RegExp(`\\b${escaped}\\b`, 'i').test(text)) {
    75→				return brand;
    76→			}
    77→		}
    78→		return null;
    79→	}
