    81→	private readonly GENDER_PRODUCT_TYPE_MAP: {
    82→		pattern: RegExp;
    83→		productTypes: string[];
    84→	}[] = [
    85→		{
    86→			pattern: /\b(women|woman|womens|women's|female|ladies|lady|girls|girl's)\b/i,
    87→			productTypes: ["Women's"],
    88→		},
    89→		{
    90→			pattern: /\b(men|man|mens|men's|male|guys|guy)\b/i,
    91→			productTypes: ['Unisex'],
    92→		},
    93→		{
    94→			pattern: /\b(youth|kids|kid|children|child|toddler|infant|baby|juvenile)\b/i,
    95→			productTypes: ['Youth'],
    96→		},
    97→	];
