    99→	private detectGenderProductTypes({ text }: { text: string }): string[] | null {
   100→		const productTypes: string[] = [];
   101→
   102→		for (const { pattern, productTypes: types } of this.GENDER_PRODUCT_TYPE_MAP) {
   103→			if (pattern.test(text)) {
   104→				productTypes.push(...types);
   105→			}
   106→		}
   107→
   108→		return productTypes.length > 0 ? productTypes : null;
   109→	}
   110→
   111→	private readonly PRICE_LEVEL_MAP: { pattern: RegExp; levels: number[] }[] = [
   112→		{
   113→			pattern:
   114→				/\b(cheap|budget|affordable|inexpensive|low[\s-]cost|economical|bargain|value|discount|basic|entry[\s-]level)\b/i,
   115→			levels: [1],
   116→		},
   117→		{
   118→			pattern:
   119→				/\b(mid[\s-]range|midrange|moderate|average|standard|medium|middle|reasonable|fair price|mid price)\b/i,
   120→			levels: [2],
   121→		},
   122→		{
   123→			pattern:
   124→				/\b(premium|luxury|high[\s-]end|expensive|upscale|top[\s-]tier|deluxe|elite|designer|exclusive|finest)\b/i,
   125→			levels: [3],
   126→		},
   127→	];
   128→
   129→	private detectPriceLevels({ text }: { text: string }): number[] | null {
   130→		const levels: number[] = [];
   131→
   132→		for (const { pattern, levels: priceLevels } of this.PRICE_LEVEL_MAP) {
   133→			if (pattern.test(text)) {
   134→				levels.push(...priceLevels);
   135→			}
   136→		}
   137→
   138→		return levels.length > 0 ? levels : null;
   139→	}
