   141→	private sanitizeQuery({ text }: { text: string }): string {
   142→		return text
   143→			.trim()
   144→			.replace(/<[^>]*>/g, ' ')
   145→			.replace(/[\x00-\x1F\x7F]/g, ' ')
   146→			.replace(/[^a-zA-Z0-9\s\-'&]/g, ' ')
   147→			.replace(/\s{2,}/g, ' ')
   148→			.substring(0, NEURAL_SEARCH_MAX_QUERY_LENGTH)
   149→			.trim();
   150→	}
   151→
   152→	private readonly QUERY_SYNONYMS: [RegExp, string][] = [
   153→		[/\btshirt(s)?\b/gi, 't-shirt$1'],
   154→		[/\bt shirt(s)?\b/gi, 't-shirt$1'],
   155→		[/\bv[\s-]?neck\b/gi, 'v-neck'],
   156→		[/\bcrew[\s-]?neck\b/gi, 'crewneck'],
   157→		[/\blong[\s-]?sleeve(s)?\b/gi, 'long-sleeve$1'],
   158→		[/\bshort[\s-]?sleeve(s)?\b/gi, 'short-sleeve$1'],
   159→		[/\bpolo[\s-]?shirt(s)?\b/gi, 'polo t-shirt$1'],
   160→		[/\bsweat[\s-]?shirt(s)?\b/gi, 'sweatshirt$1'],
   161→		[/\bsweat[\s-]?pant(s)?\b/gi, 'sweatpant$1'],
   162→		[/\bzip[\s-]?up(s)?\b/gi, 'zip-up$1'],
   163→		[/\bhalf[\s-]?zip(s)?\b/gi, 'half-zip$1'],
   164→		[/\btote[\s-]?bag(s)?\b/gi, 'tote bag$1'],
   165→		[/\bdri[\s-]?fit\b/gi, 'dri-fit'],
   166→		[/\bslim[\s-]?fit\b/gi, 'slim fit'],
   167→		[/\btank[\s-]?top(s)?\b/gi, 'tank top$1'],
   168→	];
   169→
   170→	private normalizeQuery({ text }: { text: string }): string {
   171→		let normalized = text.toLowerCase().trim();
   172→
   173→		for (const [pattern, replacement] of this.QUERY_SYNONYMS) {
   174→			normalized = normalized.replace(pattern, replacement);
   175→		}
   176→
   177→		return normalized;
   178→	}
