   377→	private normalizeCondensedFeatures({
   378→		condensedFeatures,
   379→	}: {
   380→		condensedFeatures: unknown;
   381→	}): string[] | null {
   382→		if (condensedFeatures === null || condensedFeatures === undefined) {
   383→			return null;
   384→		}
   385→
   386→		if (typeof condensedFeatures === 'string') {
   387→			return [condensedFeatures];
   388→		}
   389→
   390→		if (Array.isArray(condensedFeatures)) {
   391→			return condensedFeatures.map(String);
   392→		}
   393→
   394→		if (typeof condensedFeatures === 'object') {
   395→			return Object.values(condensedFeatures).flatMap((value: unknown) =>
   396→				Array.isArray(value) ? value.map(String) : [String(value)],
   397→			);
   398→		}
   399→
   400→		return [JSON.stringify(condensedFeatures)];
   401→	}
