   403→	private buildCombinedTextForEmbedding({ style }: { style: IStylesMvBase }): string {
   404→		const normalizedCondensedFeatures = this.normalizeCondensedFeatures({
   405→			condensedFeatures: style.condensed_features,
   406→		});
   407→		const priceLvlMap: Record<string, string> = {
   408→			1: 'Budget',
   409→			2: 'Mid-range',
   410→			3: 'Premium',
   411→		};
   412→		const mappedPriceLevel: string | null =
   413→			style.price_level && priceLvlMap[String(style.price_level)]
   414→				? (priceLvlMap[String(style.price_level)] ?? null)
   415→				: (priceLvlMap['2'] ?? null);
   416→
   417→		const parts: string[] = [
   418→			...(style.name ? [this.cleanText({ text: style.name })] : []),
   419→			...(style.product_type ? [this.cleanText({ text: style.product_type })] : []),
   420→			...(mappedPriceLevel ? [`Price lvl: ${mappedPriceLevel}`] : []),
   421→			...(style.brand?.length
   422→				? [`Brand: ${this.cleanText({ text: style.brand[0] })}`]
   423→				: []),
   424→			...(normalizedCondensedFeatures?.length
   425→				? [this.cleanText({ text: normalizedCondensedFeatures.join(', ') })]
   426→				: []),
   427→			...(style.style_type ? [this.cleanText({ text: style.style_type })] : []),
   428→			...(style.primary_category_name
   429→				? [`Category: ${this.cleanText({ text: style.primary_category_name })}`]
   430→				: []),
   431→			...(style.manufacturer
   432→				? [`From: ${this.cleanText({ text: style.manufacturer })}`]
   433→				: []),
   434→			...(style.sub_category_names?.length
   435→				? [
   436→						`Subcategories: ${this.cleanText({ text: style.sub_category_names.join(', ') })}`,
   437→					]
   438→				: []),
   439→			...(style.decoration_method
   440→				? [`Decoration: ${this.cleanText({ text: style.decoration_method })}`]
   441→				: []),
   442→			...(style.features
   443→				? [`Features: ${this.cleanText({ text: style.features })}`]
   444→				: []),
   445→		];
   446→
   447→		const combinedText = parts.filter(Boolean).join('. ');
   448→
   449→		this.logger.debug(
   450→			`Combined text length for style_id ${style.style_id}: ${combinedText.length} characters`,
   451→		);
   452→
   453→		return combinedText;
   454→	}
