   256→	private async processBatches({
   257→		batches,
   258→		concurrency,
   259→		indexName,
   260→		progressBar,
   261→		onBatchComplete,
   262→	}: {
   263→		batches: { offset: number; limit: number }[];
   264→		concurrency: number;
   265→		indexName: string;
   266→		progressBar: ProgressBar;
   267→		onBatchComplete: (indexed: number, errors: number) => void;
   268→	}): Promise<void> {
   269→		await runWithConcurrencyLimit({
   270→			items: batches,
   271→			concurrency,
   272→			handler: async (batch) => {
   273→				if (this.isCancelled) {
   274→					return { indexed: 0, errors: 0 };
   275→				}
   276→
   277→				const styles = await this.stylesMvModel.findAll({
   278→					limit: batch.limit,
   279→					offset: batch.offset,
