   345→	private setupGracefulShutdown(): void {
   346→		const signals: NodeJS.Signals[] = ['SIGTERM', 'SIGINT', 'SIGHUP', 'SIGQUIT'];
   347→
   348→		signals.forEach((signal) => {
   349→			process.on(signal, () => {
   350→				void this.handleShutdown(signal);
   351→			});
   352→		});
   353→
   354→		process.on('uncaughtException', (error) => {
   355→			this.logger.error(`Uncaught exception: ${error.message}`);
   356→			void this.handleShutdown('SIGTERM');
   357→		});
   358→
   359→		process.on('unhandledRejection', (reason) => {
   360→			this.logger.error(`Unhandled rejection: ${String(reason)}`);
   361→			void this.handleShutdown('SIGTERM');
   362→		});
   363→	}
   364→
   365→	private async handleShutdown(signal: string): Promise<void> {
   366→		if (this.isShuttingDown) {
   367→			this.logger.warn('Force shutdown requested, exiting immediately');
   368→			process.exit(1);
   369→		}
   370→
   371→		this.logger.warn(`Received ${signal} signal, initiating graceful shutdown...`);
   372→		this.isShuttingDown = true;
   373→		this.isCancelled = true;
   374→
   375→		try {
   376→			if (this.currentOperation) {
   377→				this.logger.log('Waiting for current operation to complete...');
   378→
   379→				const shutdownTimeout = setTimeout(() => {
   380→					this.logger.error('Graceful shutdown timeout, forcing exit');
   381→					process.exit(1);
   382→				}, 30000);
   383→
   384→				try {
   385→					await this.currentOperation;
   386→				} finally {
   387→					clearTimeout(shutdownTimeout);
   388→				}
   389→			}
   390→
   391→			this.logger.log('Graceful shutdown completed');
   392→			process.exit(0);
   393→		} catch (error) {
   394→			this.logger.error(`Error during shutdown: ${(error as Error).message}`);
   395→			process.exit(1);
   396→		}
   397→	}
   398→}
